export const getListStaffAvailabilityUrl = (clinicId: string,
    params?: ListStaffAvailabilityParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/clinics/${clinicId}/staff/availability?${stringifiedParams}` : `/api/clinics/${clinicId}/staff/availability`
}

