export const getGetPharmacyQueueUrl = (clinicId: string,
    params?: GetPharmacyQueueParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/clinics/${clinicId}/pharmacy/queue?${stringifiedParams}` : `/api/clinics/${clinicId}/pharmacy/queue`
}

