export const adjustStock = async (clinicId: string,
    itemId: string,
    stockAdjustInput: StockAdjustInput, options?: RequestInit): Promise<SuccessResponse> => {

  return customFetch<SuccessResponse>(getAdjustStockUrl(clinicId,itemId),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(stockAdjustInput)
  }
);}




export const getAdjustStockMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof adjustStock>>, TError,{clinicId: string;itemId: string;data: BodyType<StockAdjustInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof adjustStock>>, TError,{clinicId: string;itemId: string;data: BodyType<StockAdjustInput>}, TContext> => {

const mutationKey = ['adjustStock'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof adjustStock>>, {clinicId: string;itemId: string;data: BodyType<StockAdjustInput>}> = (props) => {
          const {clinicId,itemId,data} = props ?? {};

          return  adjustStock(clinicId,itemId,data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type AdjustStockMutationResult = NonNullable<Awaited<ReturnType<typeof adjustStock>>>
    export type AdjustStockMutationBody = BodyType<StockAdjustInput>
    export type AdjustStockMutationError = ErrorType<unknown>

    /**
 * @summary Adjust stock level
 */
export const useAdjustStock = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof adjustStock>>, TError,{clinicId: string;itemId: string;data: BodyType<StockAdjustInput>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof adjustStock>>,
        TError,
        {clinicId: string;itemId: string;data: BodyType<StockAdjustInput>},
        TContext
      > => {
      return useMutation(getAdjustStockMutationOptions(options));
    }

